class Solution:
    def insert(self, nums, n, x):
        nums.append(x)

    def heapify(self, nums, n):
        for i in range(n, 0, -1):
            parent = (i - 1) // 2
            if nums[parent] > nums[i]:
                nums[parent], nums[i] = nums[i], nums[parent]

    def solve(self, nums, n):
        self.insert(nums, n, 10)
        self.heapify(nums, n)
        print(*nums)

s = Solution()
solve = s.solve
solve([1, 3, 5], 3)

